import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is surface area?", a: "Surface area is the total area covering the outside of a three-dimensional object. It is measured in square units." },
  { q: "How do you calculate the surface area of a sphere?", a: "The surface area of a sphere is SA = 4 pi r squared where r is the radius. Square the radius, then multiply by 4 pi." },
  { q: "What is the formula for the surface area of a cylinder?", a: "The total surface area of a cylinder is SA = 2 pi r squared + 2 pi r h. The first term covers the two circular bases, and the second covers the curved side." },
  { q: "What is the difference between surface area and volume?", a: "Surface area measures the outside covering of a 3D shape in square units. Volume measures the space inside the shape in cubic units." },
  { q: "How do you calculate the surface area of a cone?", a: "The total surface area of a cone is SA = pi r squared + pi r s, where r is radius and s is slant height." },
];

type Shape = "cube" | "rectangular" | "sphere" | "cylinder" | "cone" | "pyramid";
const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(4)).toLocaleString() : "Invalid";

export default function SurfaceAreaCalculator() {
  const [shape, setShape] = useState<Shape>("rectangular");
  const [side, setSide] = useState(5);
  const [length, setLength] = useState(8);
  const [width, setWidth] = useState(5);
  const [height, setHeight] = useState(4);
  const [radius, setRadius] = useState(3);
  const [slant, setSlant] = useState(6);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    if (shape === "cube") return { area: 6 * side ** 2, formula: "SA = 6s^2", step: `SA = 6 x ${side}^2 = ${fmt(6 * side ** 2)}.` };
    if (shape === "rectangular") return { area: 2 * (length * width + length * height + width * height), formula: "SA = 2(lw + lh + wh)", step: `SA = 2(${length}x${width} + ${length}x${height} + ${width}x${height}) = ${fmt(2 * (length * width + length * height + width * height))}.` };
    if (shape === "sphere") return { area: 4 * Math.PI * radius ** 2, formula: "SA = 4pi r^2", step: `SA = 4pi x ${radius}^2 = ${fmt(4 * Math.PI * radius ** 2)}.` };
    if (shape === "cylinder") return { area: 2 * Math.PI * radius ** 2 + 2 * Math.PI * radius * height, formula: "SA = 2pi r^2 + 2pi r h", step: `SA = 2pi(${radius}^2) + 2pi(${radius})(${height}) = ${fmt(2 * Math.PI * radius ** 2 + 2 * Math.PI * radius * height)}.` };
    if (shape === "cone") return { area: Math.PI * radius ** 2 + Math.PI * radius * slant, formula: "SA = pi r^2 + pi r s", step: `SA = pi(${radius}^2) + pi(${radius})(${slant}) = ${fmt(Math.PI * radius ** 2 + Math.PI * radius * slant)}.` };
    return { area: length * width + length * slant + width * slant, formula: "SA = base area + side faces", step: `Approx. rectangular pyramid SA = ${length}x${width} + ${length}x${slant} + ${width}x${slant} = ${fmt(length * width + length * slant + width * slant)}.` };
  }, [shape, side, length, width, height, radius, slant]);

  const field = (id: string, label: string, value: number, setter: (value: number) => void) => <div><label htmlFor={id} className="text-sm font-semibold text-foreground block mb-2">{label}</label><input id={id} type="number" min="0" inputMode="decimal" value={value} onChange={(event) => setter(Number(event.target.value))} className={inputClass} /></div>;

  return (
    <>
      <SEOHead title="Free Surface Area Calculator Online - Calculate Surface Area of Any Shape Instantly | CalcHive" description="Free online surface area calculator. Calculate surface area of cube, sphere, cylinder, cone, rectangular prism and pyramid instantly. 100% free for students and everyone, no signup required." canonical="/surface-area-calculator" keywords="free surface area calculator, surface area calculator online free, calculate surface area free, sphere surface area calculator free, cylinder surface area calculator free" category="Math Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Surface Area Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free surface area calculator to calculate surface area free for common 3D shapes.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="mb-6"><label htmlFor="shape" className="text-sm font-semibold text-foreground block mb-2">Shape</label><select id="shape" value={shape} onChange={(event) => setShape(event.target.value as Shape)} className={inputClass}><option value="cube">Cube</option><option value="rectangular">Rectangular Prism</option><option value="sphere">Sphere</option><option value="cylinder">Cylinder</option><option value="cone">Cone</option><option value="pyramid">Pyramid</option></select></div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            {shape === "cube" && field("side", "Side length", side, setSide)}
            {shape === "rectangular" && <>{field("length", "Length", length, setLength)}{field("width", "Width", width, setWidth)}{field("height", "Height", height, setHeight)}</>}
            {shape === "sphere" && field("radius", "Radius", radius, setRadius)}
            {shape === "cylinder" && <>{field("radius", "Radius", radius, setRadius)}{field("height", "Height", height, setHeight)}</>}
            {shape === "cone" && <>{field("radius", "Radius", radius, setRadius)}{field("slant", "Slant height", slant, setSlant)}</>}
            {shape === "pyramid" && <>{field("length", "Base length", length, setLength)}{field("width", "Base width", width, setWidth)}{field("slant", "Slant height", slant, setSlant)}</>}
          </div>
          <motion.div key={`${shape}-${result.area}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Surface Area</p><p className="text-6xl font-black text-white tracking-tight" data-testid="result-surface-area">{fmt(result.area)}</p><p className="text-white/70 text-sm mt-1">square units</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Formula and steps</p><p className="text-sm text-foreground font-mono">{result.formula}</p><p className="text-sm text-foreground mt-1" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Surface Area of Any Shape for Free</h2><p className="text-muted-foreground leading-relaxed">Select a 3D shape, enter dimensions, and this surface area calculator online free tool applies the matching formula.</p><h2 className="text-2xl font-bold text-foreground">Surface Area Formulas for Every Common 3D Shape</h2><p className="text-muted-foreground leading-relaxed">Cubes, prisms, spheres, cylinders, cones, and pyramids all use outside-face area formulas measured in square units.</p><h2 className="text-2xl font-bold text-foreground">Free Geometry Surface Area Tool for Students</h2><p className="text-muted-foreground leading-relaxed">Use this sphere surface area calculator free and cylinder surface area calculator free for classwork and geometry checks.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/surface-area-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


